// @ts-nocheck
type SupabaseEnv = {   url?: string;   anonKey?: string;   serviceRoleKey?: string; };  export function getSupabaseEnv(): SupabaseEnv {   return {     url: process.env["SUPABASE_URL"],     anonKey: process.env["SUPABASE_ANON_KEY"],     serviceRoleKey: process.env["SUPABASE_SERVICE_ROLE_KEY"],   }; }  export function getSupabaseDatabaseUrl(): string {   return process.env["SUPABASE_DB_URL"] ?? process.env["DATABASE_URL"] ?? ""; }  export function getSupabaseFunctionsBaseUrl(): string {   const explicit = process.env["SUPABASE_FUNCTIONS_URL"]?.trim();   if (explicit) {     return explicit.replace(/\/$/, "");   }    const supabaseUrl = process.env["SUPABASE_URL"]?.trim();   if (!supabaseUrl) {     return "";   }    try {     const parsed = new URL(supabaseUrl);     const hostname = parsed.hostname.trim();     if (!hostname.endsWith(".supabase.co")) {       return "";     }      const projectRef = hostname.split(".")[0]?.trim();     if (!projectRef) {       return "";     }      return `${parsed.protocol}//${projectRef}.functions.supabase.co`;   } catch {     return "";   } }  export function getSupabasePoolConfig() {   const connectionString = getSupabaseDatabaseUrl();   if (!connectionString) {     throw new Error(       "SUPABASE_DB_URL or DATABASE_URL must be set for PostgreSQL access",     );   }    const hostname = (() => {     try {       return new URL(connectionString).hostname;     } catch {       return "";     }   })();    const ssl = hostname.includes("supabase.co")     ? { rejectUnauthorized: false }     : undefined;    return { connectionString, ssl }; }